import "jsr:@supabase/functions-js/edge-runtime.d.ts";
import { createClient } from "jsr:@supabase/supabase-js@2";
import { getCorsHeaders } from "../_shared/cors.ts";
import { getClientIp } from "../_shared/clientIp.ts";
import { buildEdgeRateLimitKey } from "../_shared/rateLimitKey.ts";

interface CodeInjectionValue {
  head?: unknown;
  body?: unknown;
}

function asString(value: unknown): string {
  return typeof value === "string" ? value : "";
}

Deno.serve(async (req: Request) => {
  if (req.method === "OPTIONS") {
    return new Response("ok", { headers: getCorsHeaders(req) });
  }

  if (req.method !== "GET" && req.method !== "POST") {
    return new Response(
      JSON.stringify({ success: false, error: "Method not allowed" }),
      {
        headers: { ...getCorsHeaders(req), "Content-Type": "application/json", Allow: "GET, POST, OPTIONS" },
        status: 405,
      },
    );
  }

  try {
    const clientIp = getClientIp(req);
    const rateLimitKey = await buildEdgeRateLimitKey("edge-code-injection", req, clientIp);
    const supabase = createClient(
      Deno.env.get("SUPABASE_URL") ?? "",
      Deno.env.get("SUPABASE_SERVICE_ROLE_KEY") ?? "",
    );

    const { data: edgeRateLimitRows, error: edgeRateError } = await supabase.rpc("consume_rate_limit", {
      p_key: rateLimitKey,
      p_max_requests: 30,
      p_window_ms: 60000,
    });

    const edgeRateLimit = Array.isArray(edgeRateLimitRows) ? edgeRateLimitRows[0] : edgeRateLimitRows;

    if (edgeRateError || !edgeRateLimit?.allowed) {
      return new Response(
        JSON.stringify({ success: false, error: "Rate limit exceeded" }),
        { headers: { ...getCorsHeaders(req), "Content-Type": "application/json" }, status: 429 },
      );
    }

    const { data, error } = await supabase
      .from("vv_site_settings")
      .select("value")
      .eq("key", "code_injection")
      .maybeSingle();

    if (error) {
      throw error;
    }

    const settings = data?.value as CodeInjectionValue | null;

    return new Response(
      JSON.stringify({
        success: true,
        head: asString(settings?.head),
        body: asString(settings?.body),
      }),
      { headers: { ...getCorsHeaders(req), "Content-Type": "application/json" } },
    );
  } catch {
    return new Response(
      JSON.stringify({ success: true, head: "", body: "" }),
      { headers: { ...getCorsHeaders(req), "Content-Type": "application/json" }, status: 200 },
    );
  }
});

const PRODUCTION_ORIGINS = [
  "https://vezvision.com",
  "https://www.vezvision.com",
] as const;

const LOCAL_ORIGINS = [
  "http://localhost:5174",
  "http://127.0.0.1:5174",
  "http://localhost:4173",
  "http://127.0.0.1:4173",
] as const;

function parseExtraOrigins(): string[] {
  const raw = Deno.env.get("ALLOWED_CORS_ORIGINS");
  if (!raw?.trim()) return [];

  return raw
    .split(",")
    .map((origin) => origin.trim())
    .filter((origin) => {
      if (!origin) return false;
      try {
        const url = new URL(origin);
        return url.protocol === "https:" || url.protocol === "http:";
      } catch {
        return false;
      }
    });
}

function getAllowedOrigins(): string[] {
  return [...PRODUCTION_ORIGINS, ...LOCAL_ORIGINS, ...parseExtraOrigins()];
}

export function getCorsHeaders(req: Request): Record<string, string> {
  const origin = req.headers.get("origin") ?? "";
  const allowedOrigins = getAllowedOrigins();
  const allowedOrigin = allowedOrigins.includes(origin) ? origin : PRODUCTION_ORIGINS[0];

  return {
    "Access-Control-Allow-Origin": allowedOrigin,
    "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
    "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
    "Access-Control-Max-Age": "86400",
  };
}

/** Browser requests include Origin; curl/scripts typically do not. */
export function hasTrustedBrowserOrigin(req: Request): boolean {
  const origin = req.headers.get("origin");
  if (!origin) return false;
  return getAllowedOrigins().includes(origin);
}

/** Edge bundle — logic mirrored in shared/clientIp.ts for unit tests. */
const IP_PATTERN = /^[\d.a-fA-F:]+$/;

function isValidIp(value: string): boolean {
  const trimmed = value.trim();
  return trimmed.length > 0 && trimmed.length <= 45 && IP_PATTERN.test(trimmed);
}

export function getClientIpFromHeaders(headers: Pick<Headers, 'get'>): string {
  const trustedHeaders = ['cf-connecting-ip', 'true-client-ip'] as const;

  for (const header of trustedHeaders) {
    const value = headers.get(header);
    if (value && isValidIp(value)) {
      return value.trim().slice(0, 45);
    }
  }

  return 'unknown';
}

export function getClientIp(req: Request): string {
  return getClientIpFromHeaders(req.headers);
}

/** Edge bundle — logic mirrored in shared/rateLimitKey.ts */

export async function sha256Hex16(input: string): Promise<string> {
  const data = new TextEncoder().encode(input);
  const hash = await crypto.subtle.digest("SHA-256", data);
  return [...new Uint8Array(hash)]
    .map((byte) => byte.toString(16).padStart(2, "0"))
    .join("")
    .slice(0, 16);
}

export async function buildEdgeRateLimitKey(
  scope: string,
  req: Pick<Request, "headers">,
  clientIp: string,
): Promise<string> {
  const userAgent = (req.headers.get("user-agent") ?? "unknown").slice(0, 120);
  const acceptLanguage = (req.headers.get("accept-language") ?? "").slice(0, 40);
  const fingerprint = await sha256Hex16(`${clientIp}|${userAgent}|${acceptLanguage}`);
  return `${scope}:${fingerprint}`;
}
